#include<iostream>
using namespace std;
int mv,mm,n,v[401],m[401],k[401],dp[401][401];
int main()
{
	cin>>mv>>mm>>n;
	for(int i=1;i<=n;i++)  cin>>v[i]>>m[i]>>k[i];
	for(int i=1;i<=n;i++){
		for(int j=mv;j>=v[i];j--){
			for(int p=mm;p>=m[i];p--){
				dp[j][p]=max(dp[j][p],dp[j-v[i]][p-m[i]]+k[i]);
			}
		}
	}
	cout<<dp[mv][mm];
	return 0;
}
